import { DNDContext } from '@affine/component';
import { AffineOtherPageLayout } from '@affine/component/affine-other-page-layout';
import { workbenchRoutes } from '@affine/core/desktop/workbench-router';
import {
  DefaultServerService,
  ServersService,
} from '@affine/core/modules/cloud';
import { GlobalDialogService } from '@affine/core/modules/dialogs';
import { DndService } from '@affine/core/modules/dnd/services';
import { GlobalContextService } from '@affine/core/modules/global-context';
import { OpenInAppGuard } from '@affine/core/modules/open-in-app';
import {
  getAFFiNEWorkspaceSchema,
  type Workspace,
  type WorkspaceMetadata,
  WorkspacesService,
} from '@affine/core/modules/workspace';
import { ZipTransformer } from '@blocksuite/affine/widgets/linked-doc';
import {
  FrameworkScope,
  LiveData,
  useLiveData,
  useService,
  useServices,
} from '@toeverything/infra';
import type { PropsWithChildren, ReactElement } from 'react';
import { useEffect, useLayoutEffect, useMemo, useRef, useState } from 'react';
import {
  matchPath,
  useLocation,
  useParams,
  useSearchParams,
} from 'react-router-dom';
import { map } from 'rxjs';
import * as _Y from 'yjs';

import { AffineErrorBoundary } from '../../../components/affine/affine-error-boundary';
import { WorkbenchRoot } from '../../../modules/workbench';
import { AppContainer } from '../../components/app-container';
import { PageNotFound } from '../404';
import { WorkspaceLayout } from './layouts/workspace-layout';
import { SharePage } from './share/share-page';

declare global {
  /**
   * @internal debug only
   */
  // oxlint-disable-next-line no-var
  var currentWorkspace: Workspace | undefined;
  // oxlint-disable-next-line no-var
  var exportWorkspaceSnapshot: (docs?: string[]) => Promise<void>;
  // oxlint-disable-next-line no-var
  var importWorkspaceSnapshot: () => Promise<void>;
  // oxlint-disable-next-line no-var
  var Y: typeof _Y;
  interface WindowEventMap {
    'affine:workspace:change': CustomEvent<{ id: string }>;
  }
}

globalThis.Y = _Y;

export const Component = (): ReactElement => {
  const {
    workspacesService,
    globalDialogService,
    serversService,
    defaultServerService,
    globalContextService,
  } = useServices({
    WorkspacesService,
    GlobalDialogService,
    ServersService,
    DefaultServerService,
    GlobalContextService,
  });

  const params = useParams();
  const location = useLocation();
  const [searchParams] = useSearchParams();

  // check if we are in detail doc route, if so, maybe render share page
  const detailDocRoute = useMemo(() => {
    const match = matchPath(
      '/workspace/:workspaceId/:docId',
      location.pathname
    );
    if (
      match &&
      match.params.docId &&
      match.params.workspaceId &&
      // TODO(eyhn): need a better way to check if it's a docId
      workbenchRoutes.find(route =>
        matchPath(route.path, '/' + match.params.docId)
      )?.path === '/:pageId'
    ) {
      return {
        docId: match.params.docId,
        workspaceId: match.params.workspaceId,
      };
    } else {
      return null;
    }
  }, [location.pathname]);

  const [workspaceNotFound, setWorkspaceNotFound] = useState(false);
  const listLoading = useLiveData(workspacesService.list.isRevalidating$);
  const workspaces = useLiveData(workspacesService.list.workspaces$);
  const meta = useMemo(() => {
    return workspaces.find(({ id }) => id === params.workspaceId);
  }, [workspaces, params.workspaceId]);

  // if listLoading is false, we can show 404 page, otherwise we should show loading page.
  useEffect(() => {
    if (listLoading === false && meta === undefined) {
      setWorkspaceNotFound(true);
    }
    if (meta) {
      setWorkspaceNotFound(false);
    }
  }, [listLoading, meta, workspacesService]);

  // if workspace is not found, we should retry
  const retryTimesRef = useRef(3);
  useEffect(() => {
    if (params.workspaceId) {
      retryTimesRef.current = 3; // reset retry times
      workspacesService.list.revalidate();
    }
  }, [params.workspaceId, workspacesService]);
  useEffect(() => {
    if (listLoading === false && meta === undefined) {
      const timer = setTimeout(() => {
        if (retryTimesRef.current > 0) {
          workspacesService.list.revalidate();
          retryTimesRef.current--;
        }
      }, 5000);
      return () => clearTimeout(timer);
    }
    return;
  }, [listLoading, meta, workspaceNotFound, workspacesService]);

  // server search params
  const serverFromSearchParams = useLiveData(
    searchParams.has('server')
      ? serversService.serverByBaseUrl$(searchParams.get('server') as string)
      : undefined
  );
  // server from workspace
  const serverFromWorkspace = useLiveData(
    meta?.flavour && meta.flavour !== 'local'
      ? serversService.server$(meta?.flavour)
      : undefined
  );
  const server = serverFromWorkspace ?? serverFromSearchParams;

  useEffect(() => {
    if (server) {
      globalContextService.globalContext.serverId.set(server.id);
      return () => {
        globalContextService.globalContext.serverId.set(
          defaultServerService.server.id
        );
      };
    }
    return;
  }, [
    defaultServerService.server.id,
    globalContextService.globalContext.serverId,
    server,
  ]);

  // if server is not found, and we have server in search params, we should show add selfhosted dialog
  const needAddSelfhosted = server === undefined && searchParams.has('server');
  // use ref to avoid useEffect trigger twice
  const addSelfhostedDialogOpened = useRef<boolean>(false);

  useEffect(() => {
    if (addSelfhostedDialogOpened.current) {
      return;
    }
    addSelfhostedDialogOpened.current = true;
    if (BUILD_CONFIG.isElectron && needAddSelfhosted) {
      globalDialogService.open('sign-in', {
        server: searchParams.get('server') as string,
      });
    }
    return;
  }, [
    globalDialogService,
    needAddSelfhosted,
    searchParams,
    serverFromSearchParams,
  ]);

  if (workspaceNotFound) {
    if (detailDocRoute) {
      return (
        <FrameworkScope scope={server?.scope}>
          <SharePage
            docId={detailDocRoute.docId}
            workspaceId={detailDocRoute.workspaceId}
          />
        </FrameworkScope>
      );
    }
    return (
      <FrameworkScope scope={server?.scope}>
        <AffineOtherPageLayout>
          <PageNotFound noPermission />
        </AffineOtherPageLayout>
      </FrameworkScope>
    );
  }
  if (!meta) {
    return <AppContainer fallback />;
  }

  return (
    <FrameworkScope scope={server?.scope}>
      <WorkspacePage meta={meta} />
    </FrameworkScope>
  );
};

const DNDContextProvider = ({ children }: PropsWithChildren) => {
  const dndService = useService(DndService);
  const contextValue = useMemo(() => {
    return {
      fromExternalData: dndService.fromExternalData,
      toExternalData: dndService.toExternalData,
    };
  }, [dndService.fromExternalData, dndService.toExternalData]);
  return (
    <DNDContext.Provider value={contextValue}>{children}</DNDContext.Provider>
  );
};

const WorkspacePage = ({ meta }: { meta: WorkspaceMetadata }) => {
  const { workspacesService, globalContextService } = useServices({
    WorkspacesService,
    GlobalContextService,
  });

  const [workspace, setWorkspace] = useState<Workspace | null>(null);

  useLayoutEffect(() => {
    const ref = workspacesService.open({ metadata: meta });
    setWorkspace(ref.workspace);
    return () => {
      ref.dispose();
    };
  }, [meta, workspacesService]);

  const rootDocReady$ = useMemo(
    () =>
      workspace
        ? LiveData.from(
            workspace.engine.doc
              .docState$(workspace.id)
              .pipe(map(v => v.ready)),
            false
          )
        : null,
    [workspace]
  );
  const isRootDocReady = useLiveData(rootDocReady$) ?? false;

  useEffect(() => {
    if (workspace) {
      // for debug purpose
      window.currentWorkspace = workspace ?? undefined;
      window.dispatchEvent(
        new CustomEvent('affine:workspace:change', {
          detail: {
            id: workspace.id,
          },
        })
      );
      window.exportWorkspaceSnapshot = async (docs?: string[]) => {
        const allMeta = workspace.docCollection.meta.docMetas;
        const stores = [];
        
        // Load all documents in the workspace (skip trashed/deleted pages)
        for (const meta of allMeta) {
          if ((meta as any).trash === true) continue;
          if (docs && !docs.includes(meta.id)) continue;
          let doc = workspace.docCollection.getDoc(meta.id);
          if (!doc) continue;
          doc.load();
          stores.push(doc.getStore());
        }

        // Wait slightly for Yjs docs to populate
        await new Promise(resolve => setTimeout(resolve, 800));

        // Intercept the download to add workspace DB docs
        const originalCreateObjectURL = window.URL.createObjectURL;
        const originalCreateElement = document.createElement.bind(document);
        let interceptedBlob: Blob | null = null;

        window.URL.createObjectURL = (obj: any) => {
          if (obj instanceof Blob && obj.type === 'application/zip') {
            interceptedBlob = obj;
            return 'blob:intercepted';
          }
          return originalCreateObjectURL(obj);
        };
        (document as any).createElement = (tagName: string, options?: any) => {
          const el = originalCreateElement(tagName, options);
          if (tagName.toLowerCase() === 'a') {
            el.click = () => {};
          }
          return el;
        };

        try {
          await ZipTransformer.exportDocs(
            workspace.docCollection,
            getAFFiNEWorkspaceSchema(),
            stores
          );
        } finally {
          window.URL.createObjectURL = originalCreateObjectURL;
          document.createElement = originalCreateElement;
        }

        if (interceptedBlob) {
          // Add workspace organization data (folders, favorites, settings, etc.)
          const fflate = await import('fflate');
          const originalZipData = fflate.unzipSync(new Uint8Array(await (interceptedBlob as Blob).arrayBuffer()));
          
          // Collect all DB sub-docs from the workspace engine
          const dbDocGuids = [
            'db$folders',
            'db$docProperties',
            'db$docCustomPropertyInfo',
            'db$pinnedCollections',
            'db$explorerIcon',
            'userdata$__local__$favorite',
            'userdata$__local__$settings',
          ];

          for (const guid of dbDocGuids) {
            try {
              const ydoc = new _Y.Doc({ guid });
              workspace.engine.doc.connectDoc(ydoc);
              // Wait for sync
              await new Promise(r => setTimeout(r, 500));
              const state = _Y.encodeStateAsUpdate(ydoc);
              if (state.length > 2) {
                originalZipData[`workspace-db/${guid}.ydoc`] = state;
              }
              workspace.engine.doc.disconnectDoc(ydoc);
            } catch (e) {
              console.warn(`Could not export db doc ${guid}`, e);
            }
          }

          // Dump the root doc containing Collections into the zip
          try {
            const rootState = _Y.encodeStateAsUpdate(workspace.rootYDoc);
            if (rootState.length > 2) {
              originalZipData[`workspace-db/root.ydoc`] = rootState;
            }
          } catch(e) {
            console.error("Failed to dump root doc", e);
          }

          // Re-zip everything
          const finalZipData = fflate.zipSync(originalZipData);
          const finalBlob = new Blob([finalZipData.buffer as ArrayBuffer], { type: 'application/zip' });

          // Download the final complete backup
          const a = originalCreateElement('a');
          a.href = originalCreateObjectURL(finalBlob);
          a.download = `${workspace.id}.bs.zip`;
          a.style.display = 'none';
          document.body.appendChild(a);
          a.click();
          a.remove();
          URL.revokeObjectURL(a.href);
        }
      };

      // oxlint-disable-next-line no-var
      (window as any).stopAutoBackup = () => {
        if ((window as any)._autoBackupIntervalId) {
          clearInterval((window as any)._autoBackupIntervalId);
          (window as any)._autoBackupIntervalId = null;
          console.log("Auto backup stopped.");
        }
      };

      (window as any).startAutoBackup = async (intervalMinutes = 10) => {
         // Stop any existing auto backup first
         (window as any).stopAutoBackup();

         try {
           const handle = await (window as any).showSaveFilePicker({
              suggestedName: `affine-workspace-backup.zip`,
              types: [{ description: 'ZIP Archive', accept: { 'application/zip': ['.zip'] } }]
           });
           console.log(`Auto backup started! Will overwrite the file every ${intervalMinutes} minutes.`);

           const runBackup = async () => {
             console.log("Generating auto backup...");
             const originalCreateObjectURL2 = window.URL.createObjectURL;
             const originalCreateElement2 = document.createElement.bind(document);
             let interceptedBlob2: Blob | null = null;

             // Mute the actual download
             window.URL.createObjectURL = (obj: any) => {
                 if (obj instanceof Blob && obj.type === 'application/zip') {
                     interceptedBlob2 = obj;
                     return 'blob:intercepted-for-autobackup';
                 }
                 return originalCreateObjectURL2(obj);
             };
             (document as any).createElement = (tagName: string, options?: any) => {
                 const el = originalCreateElement2(tagName, options);
                 if (tagName.toLowerCase() === 'a') {
                     el.click = () => {}; // Prevent click
                 }
                 return el;
             };

             try {
                 await window.exportWorkspaceSnapshot();
             } catch (e) {
                 console.error("Backup generation failed", e);
             } finally {
                 window.URL.createObjectURL = originalCreateObjectURL2;
                 document.createElement = originalCreateElement2;
             }

             if (interceptedBlob2) {
                 try {
                     const writable = await handle.createWritable();
                     await writable.write(interceptedBlob2);
                     await writable.close();
                     console.log(`Auto backup saved successfully at ${new Date().toLocaleTimeString()}`);
                 } catch(err) {
                     console.error("Failed to write to file handle. Permission lost?", err);
                 }
             }
           };

           // Run the first backup immediately
           await runBackup();

           // Then schedule recurring backups
           (window as any)._autoBackupIntervalId = setInterval(runBackup, intervalMinutes * 60 * 1000);
         } catch(e) {
           console.error("Auto backup cancelled or failed", e);
         }
      };
      window.importWorkspaceSnapshot = async () => {
        const input = document.createElement('input');
        input.type = 'file';
        input.accept = '.zip';
        input.onchange = async () => {
          if (input.files && input.files.length > 0) {
            const file = input.files[0];
            const blob = new Blob([file], { type: 'application/zip' });
            
            try {
              const fflate = await import('fflate');
              const { Transformer } = await import('@blocksuite/store');
              const zipData = fflate.unzipSync(new Uint8Array(await blob.arrayBuffer()));
              
              const job = new Transformer({
                schema: getAFFiNEWorkspaceSchema(),
                blobCRUD: workspace.docCollection.blobSync,
                docCRUD: {
                  create: (id: string) => workspace.docCollection.createDoc(id).getStore({ id }),
                  get: (id: string) => workspace.docCollection.getDoc(id)?.getStore({ id }) ?? null,
                  delete: (id: string) => workspace.docCollection.removeDoc(id),
                },
                middlewares: [] // IMPORTANT: Empty middlewares means NO replaceIdMiddleware!
              });

              const snapshotPromises: Promise<any>[] = [];

              for (const [path, data] of Object.entries(zipData)) {
                // Ignore macOS hidden files
                if (path.includes('MACOSX') || path.includes('DS_Store')) continue;

                // 1. Collect Assets
                if (path.startsWith('assets/')) {
                  const nameWithExt = path.replace('assets/', '');
                  const assetsId = nameWithExt.replace(/\.[^/.]+$/, '');
                  // Write directly to Blob storage so original sourceIds can find them
                  const fileBlob = new File([data.buffer as ArrayBuffer], nameWithExt);
                  await workspace.docCollection.blobSync.set(assetsId, fileBlob);
                  continue;
                }

                // 2. Collect Page Snapshots
                if (path.endsWith('.snapshot.json')) {
                  const json = new TextDecoder().decode(data);
                  const snapshot = JSON.parse(json);
                  snapshotPromises.push(job.snapshotToDoc(snapshot));
                  continue;
                }
              }

              // 3. Process Page Snapshots preserving their original IDs
              const newDocs = await Promise.all(snapshotPromises);
              console.log(
                'Imported Docs (Original IDs Preserved):',
                newDocs.filter(doc => !!doc).map(doc => ({ id: doc.id, title: doc.meta?.title }))
              );

              // 4. Restore Workspace DB (Organization, Folders, Favorites)
              for (const [path, data] of Object.entries(zipData)) {
                if (path === 'workspace-db/root.ydoc') {
                    console.log(`Restoring Workspace Root Doc (Collections/Settings)`);
                    _Y.applyUpdate(workspace.rootYDoc, data as Uint8Array);
                    await new Promise(r => setTimeout(r, 300));
                } else if (path.startsWith('workspace-db/') && path.endsWith('.ydoc')) {
                  const guid = path.replace('workspace-db/', '').replace('.ydoc', '');
                  console.log(`Restoring workspace DB: ${guid}`);
                  const ydoc = new _Y.Doc({ guid });
                  workspace.engine.doc.connectDoc(ydoc);
                  _Y.applyUpdate(ydoc, data as Uint8Array);
                  // Wait for sync to storage
                  await new Promise(r => setTimeout(r, 300));
                  console.log(`Restored workspace DB: ${guid}`);
                }
              }

              console.log('Workspace organization fully restored successfully!');
            } catch (e) {
              console.warn('Could not complete workspace restore', e);
            }
          }
        };
        input.click();
      };
      localStorage.setItem('last_workspace_id', workspace.id);
      globalContextService.globalContext.workspaceId.set(workspace.id);
      globalContextService.globalContext.workspaceFlavour.set(
        workspace.flavour
      );
      return () => {
        window.currentWorkspace = undefined;
        globalContextService.globalContext.workspaceId.set(null);
        globalContextService.globalContext.workspaceFlavour.set(null);
      };
    }
    return;
  }, [globalContextService, workspace]);

  if (!workspace) {
    return null; // skip this, workspace will be set in layout effect
  }

  if (!isRootDocReady) {
    return (
      <FrameworkScope scope={workspace.scope}>
        <DNDContextProvider>
          <OpenInAppGuard>
            <AppContainer fallback />
          </OpenInAppGuard>
        </DNDContextProvider>
      </FrameworkScope>
    );
  }

  return (
    <FrameworkScope scope={workspace.scope}>
      <DNDContextProvider>
        <OpenInAppGuard>
          <AffineErrorBoundary height="100vh">
            <WorkspaceLayout>
              <WorkbenchRoot />
            </WorkspaceLayout>
          </AffineErrorBoundary>
        </OpenInAppGuard>
      </DNDContextProvider>
    </FrameworkScope>
  );
};
